import React, { useState } from 'react';
import './Components.css';
import './Contact.css';

const Contact = () => {
  const [formData, setFormData] = useState({ name: "", email: "", message: "" });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    
    try {
      // Using mailto as fallback if Formspree doesn't work
      const formData_obj = new FormData();
      formData_obj.append('name', formData.name);
      formData_obj.append('email', formData.email);
      formData_obj.append('message', formData.message);
      
      const response = await fetch("https://formspree.io/f/xjvqjqpw", {
        method: "POST",
        headers: { 
          "Accept": "application/json"
        },
        body: formData_obj
      });
      
      if (response.ok) {
        setSubmitStatus('success');
        setFormData({ name: "", email: "", message: "" });
      } else {
        // Fallback to mailto
        const subject = encodeURIComponent(`Portfolio Contact from ${formData.name}`);
        const body = encodeURIComponent(`Name: ${formData.name}\nEmail: ${formData.email}\n\nMessage:\n${formData.message}`);
        window.location.href = `mailto:andyymackay@gmail.com?subject=${subject}&body=${body}`;
        setSubmitStatus('success');
        setFormData({ name: "", email: "", message: "" });
      }
      
      // Reset status after 5 seconds
      setTimeout(() => setSubmitStatus(null), 5000);
    } catch (err) {
      console.error('Form submission error:', err);
      // Fallback to mailto
      const subject = encodeURIComponent(`Portfolio Contact from ${formData.name}`);
      const body = encodeURIComponent(`Name: ${formData.name}\nEmail: ${formData.email}\n\nMessage:\n${formData.message}`);
      window.location.href = `mailto:andyymackay@gmail.com?subject=${subject}&body=${body}`;
      setSubmitStatus('success');
      setFormData({ name: "", email: "", message: "" });
      
      // Reset status after 5 seconds
      setTimeout(() => setSubmitStatus(null), 5000);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="contact-section">
      <div className="contact-scanline-layer">
  <div className="contact-scanline fuzz" style={{ top: '15%' }} />
  <div className="contact-scanline blue" style={{ top: '40%' }} />
  <div className="contact-scanline fuzz" style={{ top: '70%' }} />
      </div>
      <div className="contact-card">
        <h2>Contact Me</h2>
        {submitStatus === 'success' && (
          <div className="form-message success">
            Message sent successfully!
          </div>
        )}
        {submitStatus === 'error' && (
          <div className="form-message error">
            Failed to send message. Please try again.
          </div>
        )}
        <form onSubmit={handleSubmit} className="contact-form">
          <div className="form-group">
            <input 
              type="text" 
              placeholder="Your Name"
              value={formData.name}
              onChange={(e) => setFormData({...formData, name: e.target.value})}
              required
              className="cyber-input"
            />
            <div className="input-glow"></div>
          </div>
          <div className="form-group">
            <input 
              type="email" 
              placeholder="Your Email"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              required
              className="cyber-input"
            />
            <div className="input-glow"></div>
          </div>
          <div className="form-group">
            <textarea 
              placeholder="Your Message"
              value={formData.message}
              onChange={(e) => setFormData({...formData, message: e.target.value})}
              required
              className="cyber-textarea"
              rows="3"
            />
            <div className="input-glow"></div>
          </div>
          <button 
            type="submit" 
            className="submit-btn"
            disabled={isSubmitting}
          >
            {isSubmitting ? (
              <>
                <span className="loading-spinner"></span>
                Sending...
              </>
            ) : (
              <>
                Send Message
                <span className="btn-glow"></span>
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Contact;
